code.C:
#include <stdio.h>

int main() {
    int T, X, Y;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &X, &Y);
        if (X > Y) {
            printf("A\n");
        } else {
            printf("B\n");
        }
    }
    return 0;
}

